768: #[cfg_attr(
769:     feature = "nightly",
770:     derive(Decodable_NoContext, Encodable_NoContext, HashStable_NoContext)
771: )]
772: pub struct ProjectionPredicate<I: Interner> {
773:     pub projection_term: AliasTerm<I>,
774:     pub term: I::Term,
775: }
